import{_ as a,a as t,b as r,c as d}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Uso de enlaces magnet","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/magnet-transfer.md","filePath":"es/Other/magnet-transfer.md","lastUpdated":1781962217000}'),l={name:"es/Other/magnet-transfer.md"};function c(m,e,u,p,g,h){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="uso-de-enlaces-magnet" tabindex="-1">Uso de enlaces magnet <a class="header-anchor" href="#uso-de-enlaces-magnet" aria-label="Permalink to &quot;Uso de enlaces magnet&quot;">​</a></h1><p>La función de enlaces magnet descarga los archivos incluidos en un enlace magnet y después los sube automáticamente al canal de almacenamiento que elijas.</p><p>Es útil para transferir vídeos, episodios, archivos comprimidos y otros contenidos. Solo tienes que pegar el enlace magnet; ImgBed crea una tarea en segundo plano y, cuando termina, muestra el enlace final en la lista de subidas.</p><p><img src="'+a+'" alt="Enlace magnet" loading="lazy"></p><h2 id="donde-se-usa" tabindex="-1">Dónde se usa <a class="header-anchor" href="#donde-se-usa" aria-label="Permalink to &quot;Dónde se usa&quot;">​</a></h2><p>La entrada está en el área de subida de la página principal.</p><p>Pega el enlace magnet en el cuadro de entrada, selecciona el modo <code>Transferir</code> y sube el contenido.</p><p><img src="'+t+'" alt="Subir magnet" loading="lazy"></p><h2 id="antes-del-primer-uso" tabindex="-1">Antes del primer uso <a class="header-anchor" href="#antes-del-primer-uso" aria-label="Permalink to &quot;Antes del primer uso&quot;">​</a></h2><p>Configura primero la transferencia magnet desde el panel de administración.</p><p>Normalmente necesitas:</p><table tabindex="0"><thead><tr><th>Requisito</th><th>Para qué sirve</th></tr></thead><tbody><tr><td>Cuenta de GitHub</td><td>Ejecutar la tarea de descarga</td></tr><tr><td>Canal de subida</td><td>Google Drive, OneDrive u otro destino final</td></tr><tr><td>Directorio de destino</td><td>Carpeta donde se guardará el archivo transferido</td></tr><tr><td>Tiempo límite</td><td>Límite para tareas largas</td></tr></tbody></table><h2 id="como-transferir-un-magnet" tabindex="-1">Cómo transferir un magnet <a class="header-anchor" href="#como-transferir-un-magnet" aria-label="Permalink to &quot;Cómo transferir un magnet&quot;">​</a></h2><ol><li>Pega el enlace magnet en el cuadro de subida de la página principal.</li><li>Comprueba que el modo sea <code>Transferir</code>.</li><li>Haz clic en subir.</li><li>Espera a que ImgBed cree la tarea.</li><li>Revisa el progreso en la ventana flotante <code>Tareas magnet</code>, en la esquina inferior derecha.</li></ol><p>La descarga y la subida pueden tardar. La velocidad depende del recurso magnet, del entorno de ejecución de GitHub y del canal de almacenamiento elegido.</p><p><img src="'+r+'" alt="Descarga en curso" loading="lazy"></p><h2 id="despues-de-terminar" tabindex="-1">Después de terminar <a class="header-anchor" href="#despues-de-terminar" aria-label="Permalink to &quot;Después de terminar&quot;">​</a></h2><p>Cuando finalice la tarea, la lista de subidas mostrará el nombre del archivo y sus enlaces.</p><p>Si es un vídeo, se mostrará una vista previa de vídeo; si es una imagen, una vista previa de imagen; los demás archivos aparecerán con icono genérico.</p><p><img src="'+d+'" alt="Vídeo transferido" loading="lazy"></p><p>Puedes copiar estos formatos:</p><table tabindex="0"><thead><tr><th>Formato</th><th>Uso</th></tr></thead><tbody><tr><td>Enlace original</td><td>Abrir el archivo directamente</td></tr><tr><td>Markdown</td><td>Pegar en artículos o documentación Markdown</td></tr><tr><td>HTML</td><td>Insertar en código de una página web</td></tr><tr><td>BBCode</td><td>Usar en foros compatibles con BBCode</td></tr></tbody></table><h2 id="estados-de-la-tarea" tabindex="-1">Estados de la tarea <a class="header-anchor" href="#estados-de-la-tarea" aria-label="Permalink to &quot;Estados de la tarea&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Estado</th><th>Significado</th></tr></thead><tbody><tr><td>En espera</td><td>La tarea está creada y espera ejecución</td></tr><tr><td>Descargando</td><td>Se está descargando el recurso magnet</td></tr><tr><td>Subiendo</td><td>El archivo ya se descargó y se está subiendo al canal</td></tr><tr><td>Completado</td><td>La subida terminó y el enlace se puede copiar</td></tr><tr><td>Error</td><td>La tarea no terminó correctamente; revisa el aviso y vuelve a intentar</td></tr></tbody></table><h2 id="recomendaciones" tabindex="-1">Recomendaciones <a class="header-anchor" href="#recomendaciones" aria-label="Permalink to &quot;Recomendaciones&quot;">​</a></h2><ul><li>Si el magnet contiene varios archivos, ImgBed prioriza el archivo principal terminado.</li><li>Los archivos grandes necesitan más tiempo; espera a que termine la tarea antes de recargar la página.</li><li>Si el recurso no tiene fuentes disponibles, la descarga puede ser muy lenta o fallar.</li><li>Si la cuenta de almacenamiento no tiene cuota, permisos o directorio correcto, la subida puede fallar.</li><li>La vista previa de vídeos puede tardar unos segundos en cargarse.</li></ul>',26)])])}const _=n(l,[["render",c]]);export{v as __pageData,_ as default};
